Here is a simple batch script to check for LBA support in DOS versions:
batch
@echo off
ver | find "Version 7.0" >nul
if errorlevel 1 (
    echo This is not a DOS 7+ version.
) else (
    echo Checking for LBA support...
    if exist c:\config.sys findstr /i "LBA" c:\config.sys >nul
    if errorlevel 1 (
        echo LBA not explicitly enabled in config.sys.
    ) else (
        echo LBA support is likely enabled.
    )
)
